#ifndef mozilla_MyComponent_h_
#define mozilla_MyComponent_h_

#include "nsCOMPtr.h"
#include "nsIObserver.h"

namespace mozilla {

class MyComponent final : public nsIObserver {
 public:
  NS_DECL_ISUPPORTS
  NS_DECL_NSIOBSERVER

  MyComponent() = default;

  /**
   * Initializes the component.
   */
  nsresult Init();

  /**
   * Shuts down the component.
   */
  nsresult Shutdown();

 private:
  ~MyComponent() = default;

  // Whether the component is initialized and ready
  bool mIsInitialized = false;
};

}  // namespace mozilla

#endif  // mozilla_MyComponent_h_

